% 设置经纬度范围
load('cs.mat')

% 设置经纬度范围
min_lat = 10;
max_lat = 15;
min_lon = 140;
max_lon = 150;

% 筛选数据
data = EX1605L3MB(EX1605L3MB.lat >= min_lat & EX1605L3MB.lat <= max_lat & EX1605L3MB.lon >= min_lon & EX1605L3MB.lon <= max_lon, :);

% 计算坐标轴范围和深度范围
x_size = max_lon - min_lon;
y_size = max_lat - min_lat;
deep_min = min(data.deep);
deep_max = max(data.deep);

% 根据深度值设置像素点颜色，并绘制到图像上
scatter((data.lon - min_lon) / x_size, 1 - (data.lat - min_lat) / y_size, 3, (data.deep - deep_min) / (deep_max*0.7 - deep_min));
colormap jet;
colorbar;

% 添加高斯滤波
frgb = getframe(gca);
imrgb = frgb.cdata;
h = fspecial('gaussian', 3, 0.5);
imrgb = imfilter(imrgb, h);

% 进行高通滤波
imfft = fft2(imrgb);
H = fspecial('gaussian', size(imrgb), size(imrgb)/2);
H = 1-H;
imfftFiltered = imfft .* H;
imrgb = uint8(real(ifft2(imfftFiltered)));

% 增加对比度
